use std::path::Path;
use clui_config::Paths;

#[derive(Debug, Clone)]
pub struct Skill {
    pub name: String,
    pub path: String,
    pub overridden: bool,
}

#[derive(Debug, Clone, Default)]
pub struct SkillSet {
    pub repo: Vec<Skill>,
    pub user: Vec<Skill>,
    pub global: Vec<Skill>,
}

pub fn discover_in_dir(dir: &Path) -> Vec<Skill> {
    let Ok(entries) = std::fs::read_dir(dir) else { return Vec::new() };
    let mut skills: Vec<Skill> = entries
        .filter_map(|e| e.ok())
        .filter(|e| e.path().extension().and_then(|s| s.to_str()) == Some("md"))
        .map(|e| {
            let path = e.path();
            let name = path.file_stem().unwrap_or_default().to_string_lossy().to_string();
            Skill { name, path: path.to_string_lossy().to_string(), overridden: false }
        })
        .collect();
    skills.sort_by(|a, b| a.name.cmp(&b.name));
    skills
}

pub fn apply_override_flags(higher: &[Skill], lower: &[Skill]) -> Vec<Skill> {
    let higher_names: std::collections::HashSet<&str> =
        higher.iter().map(|s| s.name.as_str()).collect();
    lower.iter().map(|s| Skill {
        overridden: higher_names.contains(s.name.as_str()),
        ..s.clone()
    }).collect()
}

pub fn discover(cwd: &Path, paths: &Paths) -> SkillSet {
    let repo_skills_dir = cwd.join(".claude").join("skills");
    let repo = discover_in_dir(&repo_skills_dir);
    let user = discover_in_dir(&paths.claude_skills_dir);
    let global = discover_in_dir(&paths.global_skills_dir);

    let user_with_flags = apply_override_flags(&repo, &user);
    let global_with_flags = apply_override_flags(&user, &apply_override_flags(&repo, &global));

    SkillSet { repo, user: user_with_flags, global: global_with_flags }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use tempfile::tempdir;

    #[test]
    fn discovers_md_files_in_dir() {
        let dir = tempdir().unwrap();
        fs::write(dir.path().join("my-skill.md"), "# skill").unwrap();
        fs::write(dir.path().join("other.txt"), "not a skill").unwrap();
        let skills = discover_in_dir(dir.path());
        assert_eq!(skills.len(), 1);
        assert_eq!(skills[0].name, "my-skill");
    }

    #[test]
    fn higher_tier_overrides_lower() {
        let user = vec![Skill { name: "foo".into(), path: "u/foo.md".into(), overridden: false }];
        let global = vec![Skill { name: "foo".into(), path: "g/foo.md".into(), overridden: false }];
        let merged = apply_override_flags(&user, &global);
        assert!(merged[0].overridden);
    }
}
```

