#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Session {
    pub id: String,
    pub name: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StoredMessage {
    pub id: i64,
    pub session_id: String,
    pub role: String,
    pub content: String,
    pub tokens: Option<i64>,
    pub cost: Option<f64>,
    pub created_at: String,
}

pub struct Db {
    conn: Connection,
}

impl Db {
    pub fn open(path: &std::path::Path) -> Result<Self> {
        let conn = Connection::open(path)?;
        let db = Self { conn };
        db.migrate()?;
        Ok(db)
    }

    pub fn open_in_memory() -> Result<Self> {
        let conn = Connection::open_in_memory()?;
        let db = Self { conn };
        db.migrate()?;
        Ok(db)
    }

    fn migrate(&self) -> Result<()> {
        self.conn.execute_batch("
            CREATE TABLE IF NOT EXISTS sessions (
                id TEXT PRIMARY KEY,
                name TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT (datetime('now'))
            );
            CREATE TABLE IF NOT EXISTS messages (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                session_id TEXT NOT NULL,
                role TEXT NOT NULL,
                content TEXT NOT NULL,
                tokens INTEGER,
                cost REAL,
                created_at TEXT NOT NULL DEFAULT (datetime('now'))
            );
        ")?;
        Ok(())
    }

    pub fn session_count(&self) -> Result<i64> {
        Ok(self.conn.query_row(
            "SELECT COUNT(*) FROM sessions", [], |r| r.get(0)
        )?)
    }

    pub fn create_session(&self, id: &str, name: &str) -> Result<()> {
        self.conn.execute(
            "INSERT INTO sessions (id, name) VALUES (?1, ?2)",
            params![id, name],
        )?;
        Ok(())
    }

    pub fn list_sessions(&self) -> Result<Vec<Session>> {
        let mut stmt = self.conn.prepare(
            "SELECT id, name, created_at FROM sessions ORDER BY created_at DESC"
        )?;
        let rows = stmt.query_map([], |r| Ok(Session {
            id: r.get(0)?,
            name: r.get(1)?,
            created_at: r.get(2)?,
        }))?;
        Ok(rows.collect::<rusqlite::Result<Vec<_>>>()?)
    }

    pub fn insert_message(&self, session_id: &str, role: &str, content: &str,
                           tokens: Option<i64>, cost: Option<f64>) -> Result<()> {
        self.conn.execute(
            "INSERT INTO messages (session_id, role, content, tokens, cost) VALUES (?1,?2,?3,?4,?5)",
            params![session_id, role, content, tokens, cost],
        )?;
        Ok(())
    }

    pub fn messages_for_session(&self, session_id: &str) -> Result<Vec<StoredMessage>> {
        let mut stmt = self.conn.prepare(
            "SELECT id, session_id, role, content, tokens, cost, created_at
             FROM messages WHERE session_id=?1 ORDER BY id ASC"
        )?;
        let rows = stmt.query_map(params![session_id], |r| Ok(StoredMessage {
            id: r.get(0)?,
            session_id: r.get(1)?,
            role: r.get(2)?,
            content: r.get(3)?,
            tokens: r.get(4)?,
            cost: r.get(5)?,
            created_at: r.get(6)?,
        }))?;
        Ok(rows.collect::<rusqlite::Result<Vec<_>>>()?)
    }
}

