use anyhow::Result;
use serde::Deserialize;

#[derive(Debug, PartialEq)]
pub enum SseEvent {
    TextDelta(String),
    MessageDelta { output_tokens: u32 },
    MessageStop,
    Unknown,
}

#[derive(Deserialize)]
struct RawEvent {
    #[serde(rename = "type")]
    event_type: String,
    delta: Option<RawDelta>,
    usage: Option<RawUsage>,
}

#[derive(Deserialize)]
struct RawDelta {
    #[serde(rename = "type")]
    delta_type: Option<String>,
    text: Option<String>,
}

#[derive(Deserialize)]
struct RawUsage {
    output_tokens: Option<u32>,
}

pub fn parse_sse_data(data: &str) -> Result<SseEvent> {
    let raw: RawEvent = serde_json::from_str(data)?;
    Ok(match raw.event_type.as_str() {
        "content_block_delta" => {
            if let Some(delta) = raw.delta {
                if delta.delta_type.as_deref() == Some("text_delta") {
                    return Ok(SseEvent::TextDelta(delta.text.unwrap_or_default()));
                }
            }
            SseEvent::Unknown
        }
        "message_delta" => SseEvent::MessageDelta {
            output_tokens: raw.usage.and_then(|u| u.output_tokens).unwrap_or(0),
        },
        "message_stop" => SseEvent::MessageStop,
        _ => SseEvent::Unknown,
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_text_delta() {
        let data = r#"{"type":"content_block_delta","index":0,"delta":{"type":"text_delta","text":"Hello"}}"#;
        let event = parse_sse_data(data).unwrap();
        assert!(matches!(event, SseEvent::TextDelta(t) if t == "Hello"));
    }

    #[test]
    fn parses_message_stop() {
        let data = r#"{"type":"message_stop"}"#;
        let event = parse_sse_data(data).unwrap();
        assert!(matches!(event, SseEvent::MessageStop));
    }

    #[test]
    fn parses_usage() {
        let data = r#"{"type":"message_delta","delta":{"stop_reason":"end_turn"},"usage":{"output_tokens":42}}"#;
        let event = parse_sse_data(data).unwrap();
        assert!(matches!(event, SseEvent::MessageDelta { output_tokens } if output_tokens == 42));
    }

    #[test]
    fn ignores_unknown_event_types() {
        let data = r#"{"type":"ping"}"#;
        let event = parse_sse_data(data).unwrap();
        assert!(matches!(event, SseEvent::Unknown));
    }
}

use anyhow::{Context, Result};
use eventsource_stream::Eventsource;
use futures::StreamExt;
use reqwest::Client;
use serde::{Deserialize, Serialize};
use tokio::sync::mpsc;

use crate::stream::{parse_sse_data, SseEvent};

#[derive(Debug, Clone)]
pub struct AgentConfig {
    pub api_key: String,
    pub model: String,
    pub max_tokens: u32,
    pub cwd: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ApiMessage {
    pub role: String,
    pub content: String,
}

#[derive(Debug)]
pub enum AgentEvent {
    StreamChunk(String),
    MessageComplete { content: String, output_tokens: u32 },
    Error(String),
}

pub struct AgentClient {
    config: AgentConfig,
    http: Client,
    pub history: Vec<ApiMessage>,
}

impl AgentClient {
    pub fn new(config: AgentConfig) -> Self {
        Self {
            config,
            http: Client::new(),
            history: Vec::new(),
        }
    }

    pub fn reset(&mut self) {
        self.history.clear();
    }

    pub async fn send(&mut self, prompt: String, system: Option<String>,
                      tx: mpsc::Sender<AgentEvent>) -> Result<()> {
        self.history.push(ApiMessage { role: "user".into(), content: prompt });

        #[derive(Serialize)]
        struct Body<'a> {
            model: &'a str,
            max_tokens: u32,
            stream: bool,
            messages: &'a [ApiMessage],
            #[serde(skip_serializing_if = "Option::is_none")]
            system: Option<&'a str>,
        }

        let body = Body {
            model: &self.config.model,
            max_tokens: self.config.max_tokens,
            stream: true,
            messages: &self.history,
            system: system.as_deref(),
        };

        let response = self.http
            .post("https://api.anthropic.com/v1/messages")
            .header("x-api-key", &self.config.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&body)
            .send()
            .await
            .context("failed to connect to Anthropic API")?;

        if !response.status().is_success() {
            let status = response.status();
            let body_text = response.text().await.unwrap_or_default();
            let _ = tx.send(AgentEvent::Error(format!("API error {status}: {body_text}"))).await;
            return Ok(());
        }

        let mut full_content = String::new();
        let mut output_tokens = 0u32;
        let mut stream = response.bytes_stream().eventsource();

        while let Some(event_result) = stream.next().await {
            match event_result {
                Ok(event) => {
                    if event.data == "[DONE]" { break; }
                    match parse_sse_data(&event.data) {
                        Ok(SseEvent::TextDelta(text)) => {
                            full_content.push_str(&text);
                            let _ = tx.send(AgentEvent::StreamChunk(text)).await;
                        }
                        Ok(SseEvent::MessageDelta { output_tokens: n }) => {
                            output_tokens = n;
                        }
                        Ok(SseEvent::MessageStop) => break,
                        _ => {}
                    }
                }
                Err(e) => {
                    let _ = tx.send(AgentEvent::Error(e.to_string())).await;
                    break;
                }
            }
        }

        self.history.push(ApiMessage { role: "assistant".into(), content: full_content.clone() });
        let _ = tx.send(AgentEvent::MessageComplete { content: full_content, output_tokens }).await;
        Ok(())
    }
}

