use anyhow::{Context, Result};
use git2::{Repository, StatusOptions};
use std::path::Path;

#[derive(Debug, Clone, PartialEq)]
pub enum FileStatus { Modified, Added, Deleted, Renamed, Untracked }

#[derive(Debug, Clone)]
pub struct DiffEntry {
    pub path: String,
    pub status: FileStatus,
    pub staged: bool,
}

impl DiffEntry {
    pub fn status_char(&self) -> char {
        match self.status {
            FileStatus::Modified => 'M',
            FileStatus::Added => 'A',
            FileStatus::Deleted => 'D',
            FileStatus::Renamed => 'R',
            FileStatus::Untracked => '?',
        }
    }
}

#[derive(Debug, Clone, Default)]
pub struct GitStatusResult {
    pub branch: String,
    pub staged: Vec<DiffEntry>,
    pub unstaged: Vec<DiffEntry>,
}

pub fn git_status(cwd: &Path) -> Result<GitStatusResult> {
    let repo = Repository::discover(cwd)
        .context("not a git repository")?;

    let branch = repo.head()
        .ok()
        .and_then(|h| h.shorthand().map(|s| s.to_string()))
        .unwrap_or_else(|| "HEAD".to_string());

    let mut opts = StatusOptions::new();
    opts.include_untracked(true).recurse_untracked_dirs(true);
    let statuses = repo.statuses(Some(&mut opts))?;

    let mut staged = Vec::new();
    let mut unstaged = Vec::new();

    for entry in statuses.iter() {
        let path = entry.path().unwrap_or("").to_string();
        let s = entry.status();

        if s.contains(git2::Status::INDEX_MODIFIED) || s.contains(git2::Status::INDEX_NEW) || s.contains(git2::Status::INDEX_DELETED) {
            let status = if s.contains(git2::Status::INDEX_NEW) { FileStatus::Added }
                else if s.contains(git2::Status::INDEX_DELETED) { FileStatus::Deleted }
                else { FileStatus::Modified };
            staged.push(DiffEntry { path: path.clone(), status, staged: true });
        }

        if s.contains(git2::Status::WT_MODIFIED) || s.contains(git2::Status::WT_DELETED) {
            let status = if s.contains(git2::Status::WT_DELETED) { FileStatus::Deleted }
                else { FileStatus::Modified };
            unstaged.push(DiffEntry { path: path.clone(), status, staged: false });
        }

        if s.contains(git2::Status::WT_NEW) {
            unstaged.push(DiffEntry { path, status: FileStatus::Untracked, staged: false });
        }
    }

    Ok(GitStatusResult { branch, staged, unstaged })
}

pub fn stage_file(cwd: &Path, path: &str) -> Result<()> {
    let repo = Repository::discover(cwd)?;
    let mut index = repo.index()?;
    index.add_path(Path::new(path))?;
    index.write()?;
    Ok(())
}

pub fn unstage_file(cwd: &Path, path: &str) -> Result<()> {
    let repo = Repository::discover(cwd)?;
    let head = repo.head().ok().and_then(|h| h.peel_to_commit().ok());
    match head {
        Some(_) => {
            let head_obj = repo.revparse_single("HEAD")?;
            repo.reset_default(Some(&head_obj), &[Path::new(path)])?;
        }
        None => {
            let mut index = repo.index()?;
            index.remove_path(Path::new(path))?;
            index.write()?;
        }
    }
    Ok(())
}

pub fn discard_file(cwd: &Path, path: &str) -> Result<()> {
    let repo = Repository::discover(cwd)?;
    let mut checkout = git2::build::CheckoutBuilder::new();
    checkout.path(path).force();
    repo.checkout_head(Some(&mut checkout))?;
    Ok(())
}

pub fn file_diff(cwd: &Path, path: &str, staged: bool) -> Result<String> {
    let repo = Repository::discover(cwd)?;
    let mut diff_opts = git2::DiffOptions::new();
    diff_opts.pathspec(path);

    let diff = if staged {
        let head_tree = repo.head().ok()
            .and_then(|h| h.peel_to_commit().ok())
            .and_then(|c| c.tree().ok());
        let index = repo.index()?;
        repo.diff_tree_to_index(head_tree.as_ref(), Some(&index), Some(&mut diff_opts))?
    } else {
        repo.diff_index_to_workdir(None, Some(&mut diff_opts))?
    };

    let mut output = String::new();
    diff.print(git2::DiffFormat::Patch, |_, _, line| {
        let content = std::str::from_utf8(line.content()).unwrap_or("");
        output.push_str(content);
        true
    })?;
    Ok(output)
}

